-- SQL-script för att skapa WallboxChargeSession-tabellen i PostgreSQL 17
-- Används när migrations inte kan köras i produktionsmiljö

-- Skapa tabellen
CREATE TABLE IF NOT EXISTS public."WallboxChargeSession"
(
    "Id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    "Timestamp" timestamp without time zone NOT NULL,
    "SessionEnergy" integer NOT NULL,
    "SessionStartValue" bigint NOT NULL,
    "SessionStartTime" bigint NOT NULL,
    "ChargeLevel" integer NOT NULL,
    "ChargeTarget" integer NOT NULL,
    "ChargeState" text NOT NULL,
    CONSTRAINT "PK_WallboxChargeSession" PRIMARY KEY ("Id")
);

-- Skapa index på SessionStartTime för att hitta sessioner efter start-tid
CREATE INDEX IF NOT EXISTS "IX_WallboxChargeSession_SessionStartTime" 
ON public."WallboxChargeSession" ("SessionStartTime" DESC);

-- Skapa index på Timestamp för tidsbaserad sortering
CREATE INDEX IF NOT EXISTS "IX_WallboxChargeSession_Timestamp" 
ON public."WallboxChargeSession" ("Timestamp" DESC);

-- Sätt upp table comment för dokumentation
COMMENT ON TABLE public."WallboxChargeSession" IS 
'Lagrar laddningssessiondata från Wallbox-laddaren. Innehåller information om varje laddningssession.';

COMMENT ON COLUMN public."WallboxChargeSession"."Timestamp" IS 
'Tidpunkten då sessionsdata spelades in';

COMMENT ON COLUMN public."WallboxChargeSession"."SessionEnergy" IS 
'Energi förbrukad under sessionen i Wh (Watt-timmar)';

COMMENT ON COLUMN public."WallboxChargeSession"."SessionStartValue" IS 
'Startvärde för energi i Wh när sessionen började';

COMMENT ON COLUMN public."WallboxChargeSession"."SessionStartTime" IS 
'Unix timestamp (sekunder) när laddningssessionen startade';

COMMENT ON COLUMN public."WallboxChargeSession"."ChargeLevel" IS 
'Aktuell laddningsnivå i procent (0-100)';

COMMENT ON COLUMN public."WallboxChargeSession"."ChargeTarget" IS 
'Målnivå för laddning i procent (0-100)';

COMMENT ON COLUMN public."WallboxChargeSession"."ChargeState" IS 
'Aktuell status för laddningssessionen (CHARGING, IDLE, FINISHED, osv.)';
